    if isinstance(jira_data, dict):
        if 'issues' in jira_data:
            issues_obj = jira_data['issues']
            if isinstance(issues_obj, dict):
                if issue_id in issues_obj:
                    issue = issues_obj[issue_id]
                else:
                    for key, val in issues_obj.items():
                        if isinstance(val, dict) and (val.get('id') == issue_id or val.get('key') == issue_id):
                            issue = val
                            break
            elif isinstance(issues_obj, list):
                for iss in issues_obj:
                    if isinstance(iss, dict) and (iss.get('id') == issue_id or iss.get('key') == issue_id):
                        issue = iss
                        break

        if issue is None and issue_id in jira_data:
            issue = jira_data[issue_id]

        if issue is None:
            for key, val in jira_data.items():
                if isinstance(val, dict):
                    if val.get('id') == issue_id or val.get('key') == issue_id:
                        issue = val
                        break
    elif isinstance(jira_data, list):
        for iss in jira_data:
            if isinstance(iss, dict) and (iss.get('id') == issue_id or iss.get('key') == issue_id):
                issue = iss
                break

    # Collect comments from BOTH the issue object AND the top-level comments dict
    comments = []

    # 1) Comments stored on the issue itself
    if issue is not None:
        issue_comments = issue.get('comments', [])
        if isinstance(issue_comments, list):
            comments.extend(issue_comments)
        fields = issue.get('fields', {})
        if isinstance(fields, dict):
            comment_field = fields.get('comment', {})
            if isinstance(comment_field, dict):
                inner = comment_field.get('comments', [])
                if isinstance(inner, list):
                    comments.extend(inner)
            elif isinstance(comment_field, list):
                comments.extend(comment_field)

    # 2) Comments stored in the top-level 'comments' collection, keyed by issue id
    if isinstance(jira_data, dict):
        top_comments = jira_data.get('comments')
        if isinstance(top_comments, dict):
            entry = top_comments.get(issue_id)
            if isinstance(entry, list):
                comments.extend(entry)
            elif isinstance(entry, dict):
                # in case it's wrapped, e.g. {'comments': [...]}
                inner = entry.get('comments')
                if isinstance(inner, list):
                    comments.extend(inner)

    if issue is None and not comments:
        return {'pass': False, 'score': 0.0, 'feedback': f'Issue {issue_id} not found and no top-level comments for it either (loaded from {found_path}).'}

    def extract_adf_text(node):
        """Recursively pull every 'text' string out of an Atlassian Document Format dict."""
        out = []
        if isinstance(node, dict):
            if isinstance(node.get('text'), str):
                out.append(node['text'])
            for v in node.values():
                if isinstance(v, (dict, list)):
                    out.extend(extract_adf_text(v))
        elif isinstance(node, list):
            for item in node:
                out.extend(extract_adf_text(item))
        return out

    def get_comment_text(c):
        if isinstance(c, str):
            return c
        if isinstance(c, dict):
            for field in ['body', 'text', 'comment', 'content', 'message']:
                if field in c:
                    val = c[field]
                    if isinstance(val, str):
                        return val
                    if isinstance(val, (dict, list)):
                        pieces = extract_adf_text(val)
                        if pieces:
                            return ' '.join(pieces)
            return json.dumps(c)
        return str(c)

    def has_justification(text):
        return 'missing business justification/unauthorized vendor' in text.lower()

    def has_water_bottle_ref(text):
        t = text.lower()
        if 'vsm branded water bottles' in t:
            return True
        if 'water bottle' in t:
            return True
        if 'oct 1' in t:
            return True
        if 'vsm' in t and 'water' in t:
            return True
        return False

    found = False
    matching_comment = None
    for c in comments:
        text = get_comment_text(c)
        if has_water_bottle_ref(text) and has_justification(text):
            found = True
            matching_comment = text[:300]
            break

    if not found:
        comment_texts = [get_comment_text(c)[:150] for c in comments]
        return {
            'pass': False,
            'score': 0.0,
            'feedback': (
                f'{issue_id} does not contain a comment referencing '
                f'(VSM Branded Water Bottles / water bottle / Oct 1) '
                f'AND Missing business justification/unauthorized vendor. '
                f'Found {len(comments)} comment(s): {comment_texts}'
            )
        }

    return {
        'pass': True,
        'score': 1.0,
        'feedback': (
            f'{issue_id}: Found comment referencing water bottles/Oct 1 '
            f'and missing business justification/unauthorized vendor. '
            f'Matching comment excerpt: "{matching_comment}"'
        )
    }

