    }

from pathlib import Path
import json
import re

def _extract_adf_text(node):
    """Recursively extract plain text from an Atlassian Document Format node."""
    if node is None:
        return ''
    if isinstance(node, str):
        return node
    if isinstance(node, list):
        return ' '.join(_extract_adf_text(n) for n in node)
    if isinstance(node, dict):
        parts = []
        # Direct text field (ADF text nodes have type='text' and a 'text' key)
        if isinstance(node.get('text'), str):
            parts.append(node['text'])
        # Recurse into 'content' which holds child nodes
        if 'content' in node:
            parts.append(_extract_adf_text(node['content']))
        return ' '.join(p for p in parts if p)
    return ''


def _comment_to_text(comment):
    """Turn a comment entry (string or dict) into a single text string."""
    if isinstance(comment, str):
        return comment
    if not isinstance(comment, dict):
        return ''
    # Try common text-bearing fields
    for field in ['body', 'text', 'content', 'message', 'comment']:
        if field in comment:
            val = comment[field]
            if isinstance(val, str):
                return val
            if isinstance(val, dict) or isinstance(val, list):
                extracted = _extract_adf_text(val)
                if extracted:
                    return extracted
    # Fallback: stringify whole comment
    return json.dumps(comment)


def verify(workspace_path, external_services_path=None):
    # Look for jira_state.json in multiple possible locations
    paths_to_try = []
    if external_services_path:
        paths_to_try.append(Path(external_services_path) / 'jira_state.json')
    paths_to_try.append(Path(workspace_path) / 'external_data' / 'final' / 'jira_state.json')
    paths_to_try.append(Path(workspace_path) / 'jira_state.json')

    jira_data = None
    jira_path_used = None
    for p in paths_to_try:
        if p.exists():
            with open(p) as f:
                jira_data = json.load(f)
            jira_path_used = str(p)
            break

    if jira_data is None:
        return {'pass': False, 'score': 0.0,
                'feedback': 'jira_state.json not found in any expected location. Tried: '
                            + str([str(p) for p in paths_to_try])}

    ISSUE_KEY = 'OPS-4'

    # ---- Collect all comments associated with the issue from any location ----
    collected_comments = []

    if isinstance(jira_data, dict):
        # 1) Top-level 'comments' collection keyed by issue ID (the case the old verifier missed)
        top_comments = jira_data.get('comments')
        if isinstance(top_comments, dict):
            entry = top_comments.get(ISSUE_KEY)
            if isinstance(entry, list):
                collected_comments.extend(entry)
            elif entry:
                collected_comments.append(entry)
        elif isinstance(top_comments, list):
            # Possibly a flat list with issue references on each comment
            for c in top_comments:
                if isinstance(c, dict):
                    ref = c.get('issue') or c.get('issueKey') or c.get('issue_id') or c.get('key')
                    if ref == ISSUE_KEY:
                        collected_comments.append(c)

        # 2) Find the issue object itself (various shapes)
        target_issue = None
        issues_obj = jira_data.get('issues')
        if isinstance(issues_obj, dict):
            target_issue = issues_obj.get(ISSUE_KEY)
        elif isinstance(issues_obj, list):
            for issue in issues_obj:
                if isinstance(issue, dict):
                    k = issue.get('key') or issue.get('id') or ''
                    if k == ISSUE_KEY:
                        target_issue = issue
                        break
        if target_issue is None and ISSUE_KEY in jira_data:
            target_issue = jira_data[ISSUE_KEY]

        # 3) Pull comments embedded in the issue itself
        if isinstance(target_issue, dict):
            if 'comments' in target_issue:
                c = target_issue['comments']
                if isinstance(c, list):
                    collected_comments.extend(c)
                elif c:
                    collected_comments.append(c)
            if 'fields' in target_issue and isinstance(target_issue['fields'], dict):
                fields = target_issue['fields']
                cf = fields.get('comment')
                if isinstance(cf, dict) and isinstance(cf.get('comments'), list):
                    collected_comments.extend(cf['comments'])
                elif isinstance(cf, list):
                    collected_comments.extend(cf)
                if isinstance(fields.get('comments'), list):
                    collected_comments.extend(fields['comments'])

    if len(collected_comments) == 0:
        return {'pass': False, 'score': 0.0,
                'feedback': f'No comments found for issue {ISSUE_KEY} in {jira_path_used} '
                            f'(checked top-level comments dict and the issue object).'}

    # ---- Evaluate each comment ----
    for comment in collected_comments:
        text = _comment_to_text(comment)
        if not text:
            continue
        text_lower = text.lower()

        # Condition 1: vendor reference OR date reference
        has_vendor_or_date = (
            ("sullivan" in text_lower and "steakhouse" in text_lower)
            or "sullivan's steakhouse" in text_lower
            or "sullivans steakhouse" in text_lower
            or "oct 3" in text_lower
            or "october 3" in text_lower
            or "10/3" in text_lower
            or "10/03" in text_lower
        )

        # Condition 2: flag reason phrase
        has_flag_reason = 'missing business justification/unauthorized vendor' in text_lower

        if has_vendor_or_date and has_flag_reason:
            return {'pass': True, 'score': 1.0,
                    'feedback': f'Found matching comment on {ISSUE_KEY}. Excerpt: {text[:300]}'}

    # ---- Build excerpts for failure feedback ----
    excerpts = []
