from pathlib import Path
import json
import re

def extract_text_from_adf(node):
    """Walk an Atlassian Document Format dict/list and return concatenated text.
    If given a plain string, returns it. If given anything else, returns ''."""
    if node is None:
        return ""
    if isinstance(node, str):
        return node
    if isinstance(node, list):
        return " ".join(extract_text_from_adf(n) for n in node)
    if isinstance(node, dict):
        parts = []
        # ADF text nodes have a "text" string field
        if isinstance(node.get("text"), str):
            parts.append(node["text"])
        # Recurse into "content" (ADF's child container)
        if "content" in node:
            parts.append(extract_text_from_adf(node["content"]))
        return " ".join(p for p in parts if p)
    return ""


def verify(workspace_path, external_services_path=None):
