    elif isinstance(jira_data, list):
        for item in jira_data:
            if isinstance(item, dict) and (
                item.get("key") == ISSUE_KEY or item.get("id") == ISSUE_KEY or item.get("issue_key") == ISSUE_KEY
            ):
