    if isinstance(jira_data, dict) and isinstance(jira_data.get("comments"), dict):
        top_comments = jira_data["comments"].get(ISSUE_KEY)
        if isinstance(top_comments, list):
            comments.extend(top_comments)
        elif isinstance(top_comments, dict):
            comments.append(top_comments)

    # Location B: inside the issue object itself
    if isinstance(issue, dict):
        if "comments" in issue:
            c = issue["comments"]
            if isinstance(c, list):
                comments.extend(c)
            elif isinstance(c, dict):
                comments.append(c)
        elif "comment" in issue:
            c = issue["comment"]
            if isinstance(c, list):
