                else:
                    comments.append(c)
        elif "fields" in issue and isinstance(issue["fields"], dict):
            fc = issue["fields"].get("comment")
            if isinstance(fc, dict) and isinstance(fc.get("comments"), list):
                comments.extend(fc["comments"])
            elif isinstance(fc, list):
                comments.extend(fc)

    if not comments:
        return {"pass": False, "score": 0.0,
                "feedback": f"No comments found for issue {ISSUE_KEY} in either the top-level comments collection or the issue object."}

    # --- Check each comment ---
    matching_comments = []
    all_texts = []
    for comment in comments:
