            matching_comments.append(text.strip()[:200])

    if matching_comments:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"Found {len(matching_comments)} matching comment(s) on {ISSUE_KEY}. First match excerpt: {matching_comments[0]}"
        }

    return {
        "pass": False,
