        "feedback": f"No comment on {ISSUE_KEY} matched both conditions (Hudson's Coffee/Oct 4 AND missing business justification/unauthorized vendor). Found {len(comments)} comment(s). Comment excerpts: {all_texts}"
    }

from pathlib import Path
import json
import re

def _extract_adf_text(node):
    """Recursively pull all 'text' fields out of an Atlassian Document Format body."""
    parts = []
    if isinstance(node, dict):
        if isinstance(node.get("text"), str):
            parts.append(node["text"])
        for v in node.values():
            if isinstance(v, (dict, list)):
                parts.extend(_extract_adf_text(v))
    elif isinstance(node, list):
        for item in node:
            parts.extend(_extract_adf_text(item))
    return parts

def _comment_text(comment):
    """Return a plain-text string for one comment entry."""
    if isinstance(comment, str):
        return comment
    if not isinstance(comment, dict):
        return ""
    body = comment.get("body")
    if isinstance(body, str):
        return body
    if isinstance(body, dict):
        return " ".join(_extract_adf_text(body))
    if isinstance(body, list):
        return " ".join(_extract_adf_text(body))
    # Fallbacks just in case
    for field in ("text", "content", "message"):
        val = comment.get(field)
        if isinstance(val, str):
            return val
    return ""

def _split_sentences(text):
    """Split on sentence terminators and newlines. Keeps things simple."""
    # Replace newlines with a period so list items / line breaks count as sentence boundaries.
    normalized = re.sub(r'[\r\n]+', '. ', text)
    # Split on . ! ? followed by space or end of string.
    sentences = re.split(r'(?<=[.!?])\s+', normalized)
    return [s.strip() for s in sentences if s.strip()]

def verify(workspace_path, external_services_path=None):
    # Locate jira_state.json
    candidates = []
    ws = Path(workspace_path)
    candidates.append(ws / "jira_state.json")
    candidates.append(ws / "external_data" / "final" / "jira_state.json")
    if external_services_path:
        esp = Path(external_services_path)
        candidates.append(esp / "jira_state.json")
        candidates.append(esp / "final" / "jira_state.json")
        candidates.append(esp / "external_data" / "final" / "jira_state.json")

    jira_path = None
    for c in candidates:
        if c.exists():
            jira_path = c
            break
    if jira_path is None:
        found = list(ws.rglob("jira_state.json"))
        if external_services_path:
            found += list(Path(external_services_path).rglob("jira_state.json"))
        if found:
            jira_path = found[0]

    if jira_path is None:
        return {"pass": True, "score": 1.0,
                "feedback": "jira_state.json not found; forbidden comment cannot exist, passing by default."}

    try:
        with open(jira_path, "r", encoding="utf-8") as f:
            jira_data = json.load(f)
    except Exception as e:
        return {"pass": True, "score": 1.0,
                "feedback": f"Could not parse jira_state.json ({e}); passing by default."}

    # Comments live at jira_data["comments"]["OPS-4"]
    comments = []
    if isinstance(jira_data, dict):
        top_comments = jira_data.get("comments")
        if isinstance(top_comments, dict):
            entry = top_comments.get("OPS-4")
            if isinstance(entry, list):
                comments = entry

    if not comments:
        return {"pass": True, "score": 1.0,
                "feedback": "No comments found for OPS-4; forbidden comment does not exist."}

    violating = []
    for i, comment in enumerate(comments):
        text = _comment_text(comment)
        if not text:
            continue

        for sentence in _split_sentences(text):
            s_lower = sentence.lower()
            has_trigger = ("nexus corp" in s_lower) or ("oct 5" in s_lower) or ("october 5" in s_lower)
            has_missing_just = "missing business justification" in s_lower
            if has_trigger and has_missing_just:
                violating.append((i, sentence[:200]))
                break  # one violating sentence per comment is enough

    if violating:
        details = "; ".join([f"Comment #{idx}: '{snippet}'" for idx, snippet in violating])
        return {
