    def extract_text_from_description(desc):
        """Extract all text from a description field, handling both string and ADF document objects."""
        if isinstance(desc, str):
            return desc
        if isinstance(desc, dict):
            # Atlassian Document Format (ADF) - nested content[].content[].text
            texts = []
            _extract_text_recursive(desc, texts)
            return " ".join(texts)
        return ""

    def _extract_text_recursive(node, texts):
        """Recursively extract text from an ADF node."""
        if isinstance(node, dict):
            if "text" in node and isinstance(node["text"], str):
                texts.append(node["text"])
            if "content" in node and isinstance(node["content"], list):
                for child in node["content"]:
                    _extract_text_recursive(child, texts)
            # Also check other possible nested structures
            for key in ["value", "body"]:
                if key in node:
                    _extract_text_recursive(node[key], texts)
        elif isinstance(node, list):
            for item in node:
