            for key_variant in ["description", "Description", "DESCRIPTION"]:
                if key_variant in issue["fields"]:
                    candidate = issue["fields"][key_variant]
                    text = extract_text_from_description(candidate)
                    if text:
                        return text
        # Check flat keys
        for key_variant in ["description", "Description", "DESCRIPTION", "desc", "body", "Body", "details", "Details"]:
            if key_variant in issue:
                candidate = issue[key_variant]
                text = extract_text_from_description(candidate)
                if text:
                    return text
        # Check under fields for alternative names
        if "fields" in issue and isinstance(issue["fields"], dict):
            for alt in ["desc", "body", "Body", "details", "Details"]:
                if alt in issue["fields"]:
                    candidate = issue["fields"][alt]
                    text = extract_text_from_description(candidate)
                    if text:
                        return text
        return ""

    matching_issues = []
    all_summaries = []
    all_descriptions = []

    for issue in issues:
        if not isinstance(issue, dict):
            continue

        summary = get_summary(issue)
        description = get_description_text(issue)

        if summary:
            all_summaries.append(summary)
        if description:
