            "t&e-exception", "t and e exception",
            "t&amp;e exception"
        ])

        # Check for 'OPS-4' in description
        has_policy_code = "ops-hr-te-1105" in description_lower

        if has_manager_lookup and has_te_exception and has_policy_code:
            matching_issues.append(issue)

    if matching_issues:
        issue = matching_issues[0]
        summary_val = get_summary(issue)
        desc_val = get_description_text(issue)
        feedback = (f"PASS: Found matching Jira issue with 'Manager Lookup Needed' and 'T&E Exception' in summary "
                    f"and 'OPS-4' in description. Summary: '{summary_val}', "
                    f"Description (first 200 chars): '{desc_val[:200]}'.")
        return {"pass": True, "score": 1.0, "feedback": feedback}
    else:
        feedback = (f"FAIL: No Jira issue found with both 'Manager Lookup Needed' and 'T&E Exception' in "
                    f"fields.summary AND 'OPS-4' in fields.description (including nested ADF content). "
                    f"Found {len(issues)} issues total. "
