        with open(jira_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse jira_state.json: {e}"}

    issue_key = "OPS-5"
    issues = data.get("issues", {})
    issue = issues.get(issue_key)
    if issue is None:
        return {"pass": False, "score": 0.0, "feedback": f"Issue '{issue_key}' not found in issues object."}

    # Collect comments from BOTH locations:
    # 1) inside the issue object (flat or nested ADF)
    # 2) the top-level comments dict keyed by issue ID
    comments = []

    if isinstance(issue, dict):
        if "comments" in issue and isinstance(issue["comments"], list):
            comments.extend(issue["comments"])
        elif "fields" in issue and isinstance(issue["fields"], dict):
            comment_field = issue["fields"].get("comment", {})
            if isinstance(comment_field, dict) and "comments" in comment_field:
                comments.extend(comment_field["comments"])
            elif isinstance(comment_field, list):
                comments.extend(comment_field)

    # Top-level comments collection
    top_level_comments = data.get("comments", {})
    if isinstance(top_level_comments, dict):
        bucket = top_level_comments.get(issue_key)
        if isinstance(bucket, list):
            comments.extend(bucket)
        elif isinstance(bucket, dict):
            # In case it's wrapped, e.g. {"comments": [...]}
            inner = bucket.get("comments")
            if isinstance(inner, list):
                comments.extend(inner)
    elif isinstance(top_level_comments, list):
        # Fallback: a flat list where each entry tags its issue
        for c in top_level_comments:
            if isinstance(c, dict) and c.get("issue") == issue_key:
                comments.append(c)

