            if "text" in node and isinstance(node["text"], str):
                texts.append(node["text"])
            for key in ("content", "body", "value"):
                if key in node:
                    texts.append(extract_text(node[key]))
            return " ".join(texts)
        if isinstance(node, list):
            return " ".join(extract_text(item) for item in node)
        return ""

