        """Get text from a comment object, handling both plain strings and ADF bodies."""
        if isinstance(comment, str):
            return comment
        if isinstance(comment, dict):
            body = comment.get("body")
            if body is not None:
                return extract_text(body)
            for field in ("text", "content", "message"):
                val = comment.get(field)
                if isinstance(val, str):
                    return val
            return extract_text(comment)
        return str(comment)

    def normalize(text):
        text = text.lower()
        text = re.sub(r'[\u2014\u2013\u2012\u2015\u2010\u2011\uFE58\uFE63\uFF0D]', '-', text)
        return text

    required_phrases = ['t&amp;e review complete', 'all lines supported', 'ops-hr-te-1106']

    for comment in comments:
        text = get_comment_text(comment)
        norm = normalize(text)
        if all(phrase in norm for phrase in required_phrases):
            return {"pass": True, "score": 1.0, "feedback": f"Found qualifying comment on {issue_key} containing all required phrases. Comment text: {text[:300]}"}

