            check_messages(msgs, channel_info=f"IM channel: {ch_name}")

    if violating_messages:
        details = "; ".join([f"Found '{v['keyword']}' with '[T&E Review Flag]' in {v['channel_info']}: \"{v['text_snippet']}...\"" for v in violating_messages])
        return {"pass": False, "score": 0.0, "feedback": f"FAIL: Found {len(violating_messages)} violating message(s) in IM channels. {details}"}

    return {"pass": True, "score": 1.0, "feedback": "PASS: No messages found in IM channels containing '[T&E Review Flag]' along with any of 'OPS-5', 'EMP-5021', or 'Vanessa Frost'."}
